#include <stdio.h>
#include <string.h>

int maxSubstring(const char *s){
    int n=strlen(s);
    int cnt[26]={0};
    int left=0,best=0;
    for(int right=0;right<n;++right){
        int idx=s[right]-'a';
        ++cnt[idx];
        while(cnt[idx]>idx+1){
            int lidx=s[left]-'a';
            --cnt[lidx];
            ++left;
        }
        int len=right-left+1;
        if(len>best) best=len;
    }
    return best;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char s[100005];
        scanf("%s",s);
        printf("%d\n",maxSubstring(s));
    }
    return 0;
}

